module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const name = (args.name || '').trim();
const color = args.color || 'var(--accent-color)';
const align = String(args.align || 'center').toLowerCase();
const size = String(args.size || 'normal').toLowerCase();
const scale = size === 'small' ? '0.85em' : size === 'large' ? '1.3em' : '1em';
const variant = String(args.variant || 'filled').toLowerCase();
const radius = Math.max(0, Math.min(40, Number.isFinite(parseFloat(args.radius)) ? parseFloat(args.radius) : 10));
const raw = (content || '').trim();
const parts = raw.split(/\n\s*---\s*\n/);
const formula = (parts[0] || '').trim();
const legend = (parts[1] || '').trim();
return `\n\n<div class="mdp-mod-formula${variant === 'outline' ? ' mdp-fm-outline' : ''}" style="--fm-color:${color}; --fm-radius:${radius}px;">` +
  (name ? `<div class="mdp-fm-name">${esc(name)}</div>` : '') +
  `<div class="mdp-fm-body" style="text-align:${align}; font-size:${scale};">\n\n\\[ ${formula} \\]\n\n</div>` +
  (legend ? `<div class="mdp-fm-legend">\n\n${legend}\n\n</div>` : '') +
  `</div>\n\n`;
